macro_rules! generated_store_payload_accessors {
    ($as_fn:ident, $as_mut_fn:ident, $payload_field:ident, $payload_ty:ident) => {
        pub(crate) fn $as_fn(&self, node: Node) -> &$payload_ty {
            self.payloads().$payload_field(self.header(node).payload)
        }
        pub(crate) fn $as_mut_fn(&mut self, node: Node) -> &mut $payload_ty {
            let payload = self.header(node).payload;
            assert_eq!(
                payload.tag(),
                NodePayloadTag::$payload_ty,
                "payload tag mismatch"
            );
            &mut self.payloads_mut().$payload_field[Idx::from_raw(payload.raw())]
        }
    };
}
