pub(crate) fn ast_node_layout_for_payload_tag(
    tag: NodePayloadTag,
) -> Option<&'static AstNodeLayout> {
    AST_NODE_LAYOUTS.get(tag as usize)
}
impl AstStore {
    pub(crate) fn node_layout(&self, node: Node) -> &'static AstNodeLayout {
        ast_node_layout_for_payload_tag(self.header(node).payload.tag())
            .expect("generated AST layout should cover every payload tag")
    }
}
