    fn reconstruction_plan_table_fingerprint() -> u64 {
        GENERATED_RECONSTRUCTION_PLANS
            .iter()
            .fold(FNV1A_OFFSET, |hash, descriptor| {
                let hash = fnv1a_add_u64(hash, descriptor.tag as u64);
                let hash = fnv1a_add_str(hash, descriptor.factory);
                let hash = fnv1a_add_u64(hash, descriptor.arg_count as u64);
                let hash = fnv1a_add_bool(hash, descriptor.needs_original_kind);
                let hash = fnv1a_add_bool(hash, descriptor.needs_source_data);
                let hash = fnv1a_add_u64(hash, descriptor.arg_fingerprint);
                let hash = fnv1a_add_u64(hash, descriptor.child_arg_count as u64);
                fnv1a_add_u64(hash, descriptor.child_arg_fingerprint)
            })
    }
    fn child_descriptor_table_fingerprint() -> u64 {
        AST_NODE_LAYOUTS.iter().fold(FNV1A_OFFSET, |hash, layout| {
            let hash = fnv1a_add_u64(hash, layout.tag as u64);
            let hash = fnv1a_add_u64(hash, layout.child_fields.len() as u64);
            let hash = fnv1a_add_u64(hash, child_descriptor_fingerprint(layout.child_fields));
            let hash = fnv1a_add_u64(hash, layout.child_fields.len() as u64);
            fnv1a_add_u64(hash, child_traversal_fingerprint(layout.child_fields))
        })
    }
    #[test]
    fn generated_node_layouts_should_cover_payload_tags() {
        assert_eq!(AST_NODE_LAYOUTS.len(), 157);
        for (index, layout) in AST_NODE_LAYOUTS.iter().enumerate() {
            assert_eq!(
                layout.tag as usize, index,
                "payload tag discriminant should match descriptor layout order"
            );
            let found = ast_node_layout_for_payload_tag(layout.tag)
                .expect("payload tag should have a generated layout");
            assert_eq!(found.tag, layout.tag);
            assert_eq!(found.kinds, layout.kinds);
            assert_eq!(found.child_fields, layout.child_fields);
        }
    }
    #[test]
    fn generated_node_layout_kinds_should_match_payload_kind_validation() {
        let raw = ts_collections::RawIdx::from_u32(0);
        for layout in AST_NODE_LAYOUTS {
            let payload = NodePayloadId::new(layout.tag, raw);
            let mut accepted_count = 0usize;
            let mut kind = Kind::Unknown;
            while kind != Kind::Count {
                let accepts_kind = payload.matches_kind(kind);
                let layout_has_kind = layout.kinds.contains(&kind);
                if accepts_kind {
                    accepted_count += 1;
                }
                assert_eq!(
                    layout_has_kind, accepts_kind,
                    "{:?} layout kind membership should match payload validation for {:?}",
                    layout.tag, kind
                );
                kind = kind.next();
            }
            assert_eq!(
                layout.kinds.len(),
                accepted_count,
                "{:?} accepted kind count",
                layout.tag
            );
        }
    }
    #[test]
    fn generated_reconstruction_descriptors_should_match_visit_each_child_update_plan() {
        assert_eq!(GENERATED_RECONSTRUCTION_PLANS.len(), 133);
        assert_eq!(
            reconstruction_plan_table_fingerprint(),
            0xe5154fa88e9b77b2_u64
        );
        assert!(
            !GENERATED_RECONSTRUCTION_PLANS.is_empty(),
            "visit_each_child reconstruction descriptors should cover generated update arms"
        );
    }
    #[test]
    fn generated_reconstruction_descriptors_should_match_layout_child_fields() {
        for descriptor in GENERATED_RECONSTRUCTION_PLANS {
            let layout = ast_node_layout_for_payload_tag(descriptor.tag)
                .expect("payload tag should have a generated layout");
            assert_eq!(
                descriptor.child_arg_count,
                layout.child_fields.len(),
                "{:?} reconstruction should consume every layout child field",
                descriptor.tag
            );
            assert_eq!(
                descriptor.child_arg_fingerprint,
                child_traversal_fingerprint(layout.child_fields),
                "{:?} reconstruction child fields should match layout order",
                descriptor.tag
            );
        }
    }
    #[test]
    fn generated_child_descriptors_should_match_update_factory_inputs() {
        let mut actual_count = 0usize;
        let mut actual_fingerprint = FNV1A_OFFSET;
        for layout in AST_NODE_LAYOUTS {
            if layout.tag == NodePayloadTag::SourceFile || layout.child_fields.is_empty() {
                continue;
            }
            actual_count += 1;
            actual_fingerprint = fnv1a_add_u64(actual_fingerprint, layout.tag as u64);
            actual_fingerprint =
                fnv1a_add_u64(actual_fingerprint, layout.child_fields.len() as u64);
            actual_fingerprint = fnv1a_add_u64(
                actual_fingerprint,
                child_traversal_fingerprint(layout.child_fields),
            );
        }
        assert_eq!(actual_count, 133);
        assert_eq!(actual_fingerprint, 0xae0bc53028b68006_u64);
        assert!(
            98 > 0,
            "at least one update wrapper should exercise descriptor-driven child comparison"
        );
    }
    #[test]
    fn generated_child_descriptors_should_match_schema_and_traversal_shape() {
        assert_eq!(AST_NODE_LAYOUTS.len(), 157);
        assert_eq!(child_descriptor_table_fingerprint(), 0x2a2cd64ad9bb51e7_u64);
    }
