    fn visit_child_field_with_lists<FNode, FNodes, FModifiers>(
        &self,
        node: Node,
        field: &AstChildFieldDescriptor,
        visit_node: &mut FNode,
        visit_nodes: &mut FNodes,
        visit_modifiers: &mut FModifiers,
    ) -> ControlFlow<()>
    where
        FNode: FnMut(Option<Node>) -> ControlFlow<()>,
        FNodes: FnMut(SourceNodeList<'_>) -> ControlFlow<()>,
        FModifiers: FnMut(SourceModifierList<'_>) -> ControlFlow<()>,
    {
        match self.child_field_value(node, field) {
            AstChildFieldValue::Node(Some(child)) => visit_node(Some(child))?,
            AstChildFieldValue::Node(None) => {}
            AstChildFieldValue::NodeList(Some(nodes)) => visit_nodes(nodes)?,
            AstChildFieldValue::NodeList(None) => {}
            AstChildFieldValue::ModifierList(Some(modifiers)) => visit_modifiers(modifiers)?,
            AstChildFieldValue::ModifierList(None) => {}
            AstChildFieldValue::RawNodeSlice(Some(nodes)) => {
                for child in nodes.iter() {
                    visit_node(child)?;
                }
            }
            AstChildFieldValue::RawNodeSlice(None) => {}
        }
        ControlFlow::Continue(())
    }
    fn for_each_child_field<F>(
        &self,
        node: Node,
        field: &AstChildFieldDescriptor,
        visitor: &mut F,
    ) -> ControlFlow<()>
    where
        F: FnMut(Option<Node>) -> ControlFlow<()>,
    {
        match self.child_field_value(node, field) {
            AstChildFieldValue::Node(Some(child)) => visitor(Some(child))?,
            AstChildFieldValue::Node(None) => {}
            AstChildFieldValue::NodeList(Some(nodes)) => {
                for child in nodes.iter() {
                    visitor(Some(child))?;
                }
            }
            AstChildFieldValue::NodeList(None) => {}
            AstChildFieldValue::ModifierList(Some(modifiers)) => {
                for child in modifiers.iter() {
                    visitor(Some(child))?;
                }
            }
            AstChildFieldValue::ModifierList(None) => {}
            AstChildFieldValue::RawNodeSlice(Some(nodes)) => {
                for child in nodes.iter() {
                    visitor(child)?;
                }
            }
            AstChildFieldValue::RawNodeSlice(None) => {}
        }
        ControlFlow::Continue(())
    }
    #[inline]
    pub fn for_each_child<F>(&self, node: Node, mut visitor: F) -> ControlFlow<()>
    where
        F: FnMut(Option<Node>) -> ControlFlow<()>,
    {
        for field in self.node_layout(node).child_fields {
            self.for_each_child_field(node, field, &mut visitor)?;
        }
        ControlFlow::Continue(())
    }
