    fn deep_clone_child_field_from_clone_source_with_location(
        &mut self,
        source: DeepCloneSource<'_>,
        node: Node,
        field: &AstChildFieldDescriptor,
        synthetic_location: bool,
    ) -> GeneratedChildFieldValue {
        match field.kind {
            AstChildFieldKind::Node | AstChildFieldKind::OptionalNode => {
                let source_node = source.with_store(&self.store, |source_store| match source_store
                    .child_field_value(node, field)
                {
                    AstChildFieldValue::Node(node) => node,
                    _ => panic!("generated child descriptor kind should match clone node value"),
                });
                GeneratedChildFieldValue::Node(source_node.map(|node| {
                    self.deep_clone_node_from_clone_source_with_location(
                        source,
                        node,
                        synthetic_location,
                    )
                }))
            }
            AstChildFieldKind::NodeList | AstChildFieldKind::OptionalNodeList => {
                let source_nodes =
                    source.with_store(&self.store, |source_store| {
                        match source_store.child_field_value(node, field) {
                            AstChildFieldValue::NodeList(nodes) => nodes.map(|nodes| nodes.id()),
                            _ => panic!(
                                "generated child descriptor kind should match clone node-list value"
                            ),
                        }
                    });
                GeneratedChildFieldValue::NodeList(source_nodes.map(|nodes| {
                    NodeList::from_id(self.deep_clone_node_list_from_clone_source_with_location(
                        source,
                        nodes,
                        synthetic_location,
                    ))
                }))
            }
            AstChildFieldKind::ModifierList | AstChildFieldKind::OptionalModifierList => {
                let source_modifiers = source.with_store(&self.store, |source_store| {
                    match source_store.child_field_value(node, field) {
                        AstChildFieldValue::ModifierList(modifiers) => {
                            modifiers.map(|modifiers| modifiers.id())
                        }
                        _ => panic!(
                            "generated child descriptor kind should match clone modifier-list value"
                        ),
                    }
                });
                GeneratedChildFieldValue::ModifierList(source_modifiers.map(|modifiers| {
                    ModifierList::from_id(
                        self.deep_clone_modifier_list_from_clone_source_with_location(
                            source,
                            modifiers,
                            synthetic_location,
                        ),
                    )
                }))
            }
            AstChildFieldKind::RawNodeSlice | AstChildFieldKind::OptionalRawNodeSlice => {
                let source_nodes = source.with_store(&self.store, |source_store| match source_store.child_field_value(node, field) {
                        AstChildFieldValue::RawNodeSlice(nodes) => nodes.map(|nodes| nodes.id()),
                        _ => panic!("generated child descriptor kind should match clone raw-node-slice value"),
                    });
                GeneratedChildFieldValue::RawNodeSlice(source_nodes.map(|nodes| {
                    RawNodeSlice::from_id(
                        self.deep_clone_raw_node_slice_from_clone_source_with_location(
                            source,
                            nodes,
                            synthetic_location,
                        ),
                    )
                }))
            }
        }
    }
    fn deep_clone_child_fields_from_clone_source_with_location(
        &mut self,
        source: DeepCloneSource<'_>,
        node: Node,
        synthetic_location: bool,
    ) -> GeneratedChildFieldValues {
        let layout = source.with_store(&self.store, |source_store| source_store.node_layout(node));
        let mut fields = [GeneratedChildFieldValue::Missing; GENERATED_CHILD_FIELD_CAPACITY];
        let mut len = 0usize;
        for field in layout.child_fields {
            fields[len] = self.deep_clone_child_field_from_clone_source_with_location(
                source,
                node,
                field,
                synthetic_location,
            );
            len += 1;
        }
        GeneratedChildFieldValues { fields, len }
    }
