#[cfg(test)]
mod generated_ast_view_tests {
    use super::*;
    fn empty_node_list(factory: &mut NodeFactory) -> NodeList {
        factory.new_node_list(
            core::TextRange::new(0, 0),
            core::TextRange::new(0, 0),
            std::iter::empty::<Node>(),
        )
    }
    #[test]
    fn payload_views_should_cast_by_payload_tag_and_kind() {
        let mut factory = NodeFactory::default();
        let identifier = factory.new_identifier("value");
        let identifier_view = factory.store().view::<IdentifierView>(identifier).unwrap();
        assert_eq!(identifier_view.node(), identifier);
        assert!(factory.store().view::<TokenView>(identifier).is_none());
    }
    #[test]
    fn category_views_should_cast_from_generated_payload_sets() {
        let mut factory = NodeFactory::default();
        let name = factory.new_identifier("fn_name");
        let type_node = factory.new_keyword_type_node(Kind::StringKeyword);
        let value = factory.new_numeric_literal("1", TokenFlags::NONE);
        let statements = empty_node_list(&mut factory);
        let block = factory.new_block(statements, false);
        let parameters = empty_node_list(&mut factory);
        let function = factory.new_function_declaration(
            None::<ModifierList>,
            None::<Node>,
            Some(name),
            None::<NodeList>,
            parameters,
            Some(type_node),
            None::<Node>,
            Some(block),
        );
        assert!(factory.store().view::<AstNameView>(name).is_some());
        assert!(factory.store().view::<AstTypeNodeView>(type_node).is_some());
        assert!(factory.store().view::<AstExpressionView>(value).is_some());
        assert!(factory.store().view::<AstStatementView>(block).is_some());
        assert!(
            factory
                .store()
                .view::<AstDeclarationView>(function)
                .is_some()
        );
        assert!(
            factory
                .store()
                .view::<AstExpressionView>(function)
                .is_none()
        );
    }
    #[test]
    fn ast_ref_should_delegate_to_descriptor_children() {
        let mut factory = NodeFactory::default();
        let name = factory.new_identifier("fn_name");
        let parameters = empty_node_list(&mut factory);
        let function = factory.new_function_declaration(
            None::<ModifierList>,
            None::<Node>,
            Some(name),
            None::<NodeList>,
            parameters,
            None::<Node>,
            None::<Node>,
            None::<Node>,
        );
        let function_ref = factory
            .store()
            .ast_ref::<FunctionDeclarationView>(function)
            .unwrap();
        assert_eq!(function_ref.kind(), Kind::FunctionDeclaration);
        let name_field = function_ref
            .child_fields()
            .iter()
            .find(|field| field.name == "name")
            .unwrap();
        match function_ref.child_field_value(name_field) {
            AstChildFieldValue::Node(Some(child)) => assert_eq!(child, name),
            AstChildFieldValue::Node(None) => panic!("expected generated name child"),
            _ => panic!("expected generated name child descriptor to be a node field"),
        }
    }
    #[test]
    fn ast_ref_child_helpers_should_cast_descriptor_children() {
        let mut factory = NodeFactory::default();
        let name = factory.new_identifier("fn_name");
        let parameter_name = factory.new_identifier("param");
        let parameter = factory.new_parameter_declaration(
            None::<ModifierList>,
            None::<Node>,
            Some(parameter_name),
            None::<Node>,
            None::<Node>,
            None::<Node>,
        );
        let parameters = factory.new_node_list(
            core::TextRange::new(0, 0),
            core::TextRange::new(0, 0),
            [parameter],
        );
        let function = factory.new_function_declaration(
            None::<ModifierList>,
            None::<Node>,
            Some(name),
            None::<NodeList>,
            parameters,
            None::<Node>,
            None::<Node>,
            None::<Node>,
        );
        let function_ref = factory
            .store()
            .ast_ref::<FunctionDeclarationView>(function)
            .unwrap();
        let name_ref = function_ref.name::<IdentifierView>().unwrap();
        assert_eq!(name_ref.node(), name);
        assert!(function_ref.name::<AstStatementView>().is_none());
        let parameter_nodes = function_ref
            .parameters::<ParameterDeclarationView>()
            .map(|child| child.node())
            .collect::<Vec<_>>();
        assert_eq!(parameter_nodes, vec![parameter]);
        let mut visited_parameter = None;
        let result = function_ref.for_each_child_list_node(AstChildFieldId::Parameters, |child| {
            visited_parameter = Some(child);
            ControlFlow::Break(())
        });
        assert_eq!(result, ControlFlow::Break(()));
        assert_eq!(visited_parameter, Some(parameter));
        let found_parameter = function_ref
            .find_parameters::<ParameterDeclarationView>(|child| child.node() == parameter)
            .unwrap();
        assert_eq!(found_parameter.node(), parameter);
        let expression_nodes = function_ref
            .parameters::<AstExpressionView>()
            .map(|child| child.node())
            .collect::<Vec<_>>();
        assert!(expression_nodes.is_empty());
        let expression = function_ref.find_parameters::<AstExpressionView>(|_| true);
        assert!(expression.is_none());
    }
}
macro_rules! generated_alloc_payload {
    ($factory:expr, $payload_field:ident, $payload_tag:ident, $data:expr) => {{
        let payload_idx = ($factory).store.payloads_mut().$payload_field.alloc($data);
        NodePayloadId::new(NodePayloadTag::$payload_tag, payload_idx.into_raw())
    }};
}
macro_rules! generated_update_node {
        ($factory:expr, $node:expr, $original_metadata:expr, $changed:expr, $constructor:ident($($arg:expr),* $(,)?)) => {{
            if !$changed { return $node; }
            let updated = ($factory).$constructor($($arg),*);
            ($factory).finish_update_node(updated, $node, $original_metadata)
        }};
    }
macro_rules! generated_update_node_from_store {
        ($factory:expr, $source:expr, $node:expr, $original_metadata:expr, $changed:expr, imports($($arg_name:ident = $arg:expr),* $(,)?), $constructor:ident($($factory_arg:expr),* $(,)?)) => {{
            if !$changed { return ($factory).finish_unchanged_update_from_store($source, $node); }
            $(let $arg_name = $arg;)*
            let updated = ($factory).$constructor($($factory_arg),*);
            ($factory).finish_update_node(updated, $node, $original_metadata)
        }};
    }
