    pub(crate) fn finish_update_node(
        &mut self,
        updated: Node,
        original: Node,
        original_metadata: NodeUpdateMetadata,
    ) -> Node {
        if updated != original {
            self.store.set_flags(updated, original_metadata.flags);
            self.store.set_loc(updated, original_metadata.loc);
            if let Some(on_update) = &self.hooks.on_update {
                on_update(&self.store, updated, original);
            }
        }
        updated
    }
    pub(crate) fn finish_clone_node(
        &mut self,
        cloned: Node,
        original: Node,
        original_flags: NodeFlags,
        original_loc: core::TextRange,
    ) -> Node {
        let cloned = self.finish_update_node(
            cloned,
            original,
            NodeUpdateMetadata {
                flags: original_flags,
                loc: original_loc,
            },
        );
        if let Some(recorder) = &mut self.clone_recorder {
            recorder.insert_same_store(original, cloned);
        }
        if cloned != original {
            if let Some(on_clone) = &self.hooks.on_clone {
                on_clone(&self.store, cloned, original);
            }
        }
        cloned
    }
